import React, { useEffect, useState } from 'react';
import { dashboardAPI } from '../../services/api';
import Card from '../../components/common/Card';
import StatCard from '../../components/common/StatCard';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend } from 'recharts';
import { Users, GraduationCap, AlertTriangle, BookOpen, TrendingUp, Activity } from 'lucide-react';

const AdminDashboard = () => {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      const response = await dashboardAPI.getStats();
      if (response.data.success) {
        setStats(response.data.statistics);
      }
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-20">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444'];

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Welcome Header */}
      <div className="bg-gradient-to-r from-purple-600 via-purple-700 to-purple-800 rounded-2xl p-8 text-white relative overflow-hidden">
        <div className="absolute top-0 right-0 w-40 h-40 bg-white/10 rounded-full -translate-y-1/2 translate-x-1/2"></div>
        <div className="absolute bottom-0 left-1/4 w-20 h-20 bg-white/5 rounded-full translate-y-1/2"></div>
        <div className="relative z-10">
          <div className="flex items-center gap-2 text-purple-200 mb-2">
            <TrendingUp className="w-5 h-5" />
            <span className="text-sm font-medium">System Overview</span>
          </div>
          <h1 className="text-3xl font-bold mb-2">Admin Dashboard</h1>
          <p className="text-purple-100">Monitor and manage the entire system from one place</p>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-5">
        <StatCard
          title="Total Students"
          value={stats?.totalStudents || 0}
          icon={GraduationCap}
          color="blue"
          subtitle="Enrolled"
        />
        <StatCard
          title="Total Faculty"
          value={stats?.totalTeachers || 0}
          icon={Users}
          color="green"
          subtitle="Active members"
        />
        <StatCard
          title="Capstone Advisers"
          value={stats?.capstoneAdvisersAvailable || 0}
          icon={BookOpen}
          color="purple"
          subtitle="Available"
        />
        <StatCard
          title="Pending Violations"
          value={stats?.violationsSummary?.find(v => v.status === 'Pending')?.count || 0}
          icon={AlertTriangle}
          color="orange"
          subtitle="Requires action"
        />
      </div>

      {/* Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Students per Year Level */}
        <Card title="Students per Year Level" icon={GraduationCap}>
          <ResponsiveContainer width="100%" height={300}>
            <BarChart data={stats?.studentsPerYear || []}>
              <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" />
              <XAxis dataKey="year_level" tick={{ fill: '#64748b', fontSize: 12 }} />
              <YAxis tick={{ fill: '#64748b', fontSize: 12 }} />
              <Tooltip 
                contentStyle={{ 
                  backgroundColor: '#fff', 
                  border: '1px solid #e2e8f0',
                  borderRadius: '8px',
                  boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)'
                }} 
              />
              <Bar dataKey="count" fill="url(#colorGradient)" radius={[6, 6, 0, 0]} />
              <defs>
                <linearGradient id="colorGradient" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="0%" stopColor="#3b82f6" />
                  <stop offset="100%" stopColor="#1d4ed8" />
                </linearGradient>
              </defs>
            </BarChart>
          </ResponsiveContainer>
        </Card>

        {/* Violations Summary */}
        <Card title="Violations Summary" icon={AlertTriangle}>
          <ResponsiveContainer width="100%" height={300}>
            <PieChart>
              <Pie
                data={stats?.violationsSummary || []}
                cx="50%"
                cy="50%"
                labelLine={false}
                label={({ status, count }) => `${status}: ${count}`}
                outerRadius={100}
                fill="#8884d8"
                dataKey="count"
                nameKey="status"
              >
                {stats?.violationsSummary?.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={index === 0 ? '#f59e0b' : '#10b981'} />
                ))}
              </Pie>
              <Tooltip 
                contentStyle={{ 
                  backgroundColor: '#fff', 
                  border: '1px solid #e2e8f0',
                  borderRadius: '8px',
                  boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)'
                }} 
              />
            </PieChart>
          </ResponsiveContainer>
        </Card>

        {/* Faculty Employment Status */}
        <Card title="Faculty Employment Status" icon={Users}>
          <ResponsiveContainer width="100%" height={300}>
            <PieChart>
              <Pie
                data={stats?.facultyEmployment || []}
                cx="50%"
                cy="50%"
                labelLine={false}
                label={({ employment_status, count }) => `${employment_status}: ${count}`}
                outerRadius={100}
                fill="#8884d8"
                dataKey="count"
                nameKey="employment_status"
              >
                {stats?.facultyEmployment?.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Pie>
              <Tooltip 
                contentStyle={{ 
                  backgroundColor: '#fff', 
                  border: '1px solid #e2e8f0',
                  borderRadius: '8px',
                  boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)'
                }} 
              />
            </PieChart>
          </ResponsiveContainer>
        </Card>

        {/* Recent Activity */}
        <Card title="Recent Activity" icon={Activity}>
          <div className="space-y-3 max-h-[300px] overflow-y-auto">
            {stats?.recentActivity?.map((log) => (
              <div key={log.id} className="flex items-start gap-3 py-3 border-b border-secondary-100 last:border-0 hover:bg-secondary-50 -mx-2 px-2 rounded-lg transition-colors">
                <div className="w-2 h-2 bg-primary-500 rounded-full mt-2 flex-shrink-0"></div>
                <div className="flex-1 min-w-0">
                  <p className="text-sm text-secondary-800 font-medium">{log.action}</p>
                  <p className="text-xs text-secondary-500 mt-0.5">
                    {log.username || 'System'} • {new Date(log.created_at).toLocaleString()}
                  </p>
                </div>
              </div>
            ))}
            {(!stats?.recentActivity || stats.recentActivity.length === 0) && (
              <div className="empty-state py-8">
                <Activity className="w-10 h-10" />
                <p className="text-sm">No recent activity</p>
              </div>
            )}
          </div>
        </Card>
      </div>
    </div>
  );
};

export default AdminDashboard;
